content:
{
  "sentences": [
    {
      "text": "這家餐廳的價格比那家便宜很多。",
      "pinyin": "Zhè jiā cāntīng de jiàgé bǐ nà jiā piányí hěn duō.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de0 jia4ge2 bi3 na4 jia1 pian2yi2 hen3 duo1.",
      "translation_en": "The price at this restaurant is much cheaper than that one.",
      "translation_ko": "이 식당의 가격은 저 식당보다 훨씬 저렴합니다."
    },
    {
      "text": "牛肉麵的味道比滷肉飯更濃。",
      "pinyin": "Niúròu miàn de wèidào bǐ lǔròu fàn gèng nóng.",
      "pinyin_numeric": "niu2rou4 mian4 de0 wei4dao4 bi3 lu3rou4 fan4 geng4 nong2.",
      "translation_en": "The flavor of beef noodle soup is richer than braised pork rice.",
      "translation_ko": "소고기 국수의 맛은 루로우판보다 더 진합니다."
    },
    {
      "text": "便利商店的距離比超市近很多。",
      "pinyin": "Biànlì shāngdiàn de jùlí bǐ chāoshì jìn hěn duō.",
      "pinyin_numeric": "bian4li4 shang1dian4 de0 ju4li2 bi3 chao1shi4 jin4 hen3 duo1.",
      "translation_en": "The convenience store is much closer than the supermarket.",
      "translation_ko": "편의점은 슈퍼마켓보다 훨씬 가깝습니다."
    },
    {
      "text": "珍珠奶茶的甜度比紅茶高。",
      "pinyin": "Zhēnzhū nǎichá de tiándù bǐ hóngchá gāo.",
      "pinyin_numeric": "zhen1zhu1 nai3cha2 de0 tian2du4 bi3 hong2cha2 gao1.",
      "translation_en": "Bubble milk tea is sweeter than black tea.",
      "translation_ko": "버블 밀크티는 홍차보다 단맛이 더 높습니다."
    },
    {
      "text": "夜市的氣氛比小吃店熱鬧。",
      "pinyin": "Yèshì de qìfēn bǐ xiǎochī diàn rènào.",
      "pinyin_numeric": "ye4shi4 de0 qi4fen1 bi3 xiao3chi1 dian4 re4nao4.",
      "translation_en": "The atmosphere at the night market is livelier than at a small eatery.",
      "translation_ko": "야시장의 분위기는 작은 음식점보다 더 활기찹니다."
    },
    {
      "text": "這份炒飯的份量比那份多。",
      "pinyin": "Zhè fèn chǎofàn de fènliàng bǐ nà fèn duō.",
      "pinyin_numeric": "zhe4 fen4 chao3fan4 de0 fen4liang4 bi3 na4 fen4 duo1.",
      "translation_en": "This serving of fried rice is larger than that one.",
      "translation_ko": "이 볶음밥의 양은 저 볶음밥보다 더 많습니다."
    },
    {
      "text": "坐捷運比坐公車方便。",
      "pinyin": "Zuò jiéyùn bǐ zuò gōngchē fāngbiàn.",
      "pinyin_numeric": "zuo4 jie2yun4 bi3 zuo4 gong1che1 fang1bian4.",
      "translation_en": "Taking the MRT is more convenient than taking the bus.",
      "translation_ko": "지하철을 타는 것이 버스를 타는 것보다 더 편리합니다."
    },
    {
      "text": "這家店的服務態度比那家好。",
      "pinyin": "Zhè jiā diàn de fúwù tàidù bǐ nà jiā hǎo.",
      "pinyin_numeric": "zhe4 jia1 dian4 de0 fu2wu4 tai4du4 bi3 na4 jia1 hao3.",
      "translation_en": "The service attitude at this shop is better than that one.",
      "translation_ko": "이 가게의 서비스 태도는 저 가게보다 더 좋습니다."
    },
    {
      "text": "雞排的口感比豆腐更脆。",
      "pinyin": "Jīpái de kǒugǎn bǐ dòufu gèng cuì.",
      "pinyin_numeric": "ji1pai2 de0 kou3gan3 bi3 dou4fu0 geng4 cui4.",
      "translation_en": "The texture of chicken cutlet is crispier than tofu.",
      "translation_ko": "치킨 커틀릿의 식감은 두부보다 더 바삭합니다."
    },
    {
      "text": "這家餐廳的環境比那家安靜。",
      "pinyin": "Zhè jiā cāntīng de huánjìng bǐ nà jiā ānjìng.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de0 huan2jing4 bi3 na4 jia1 an1jing4.",
      "translation_en": "The environment at this restaurant is quieter than that one.",
      "translation_ko": "이 식당의 환경은 저 식당보다 더 조용합니다."
    }
  ]
}
